# Load configuration
def load_config(config_path='clustering_config.json'):
    """Load clustering configuration from JSON file"""
    try:
        with open(config_path, 'r') as f:
            config = json.load(f)
        print(f"Loaded configuration from {config_path}")
        return config
    except FileNotFoundError:
        print(f"Warning: Configuration file {config_path} not found. Using default values.")
        return get_default_config()

def get_default_config():
    """Return default configuration if config file is missing"""
    return {
        "clustering": {
            "max_cluster_size": 25,
            "min_cluster_size": 3,
            "initial_clusters": 20,
            "refinement_threshold": 0.5,
            "linkage_method": "ward"
        },
        "distance_weights": {
            "individual_notebooks": {
                "edit_distance": 0.25,
                "complexity_features": 0.25,
                "state_distribution": 0.15,
                "transition_matrix": 0.15,
                "length_similarity": 0.10,
                "pattern_similarity": 0.10
            },
            "inter_cluster": {
                "complexity_features": 0.35,
                "state_distribution": 0.25,
                "transition_matrix": 0.25,
                "length_similarity": 0.15
            }
        },
        "similarity_methods": {
            "transition_matrix_method": "frobenius",
            "ngram_sizes": [2, 3]
        },
        "processing": {
            "state_range": {"min": 0, "max": 11},
            "laplace_smoothing": 1e-6,
            "entropy_epsilon": 1e-10,
            "min_sequence_length": 1
        },
        "sorting": {
            "cluster_order_ascending": [True, True, False],
            "cluster_order_columns": ["cluster_order", "cluster_id", "sequence_length"]
        },
        "random_seed": 42
    }

# Global configuration
CONFIG = load_config()

class NotebookSequence:
    """Enhanced class to represent a notebook sequence with advanced complexity features and HMM analysis"""
    
    def __init__(self, kernel_id, sequence, n_states=12, config=None):
        self.kernel_id = kernel_id
        self.sequence = np.array(sequence)
        self.sequence_ngrams = set([x for l in [self.get_ngrams(sequence, n) for n in config["similarity_methods"]["ngram_sizes"]] for x in l])
        self.n_states = n_states
        self.transition_matrix = None
        self.state_distribution = None
        self.complexity_features = None
        self.complexity_features_normalized = None
        
        # Use provided config or global config
        self.config = config if config is not None else CONFIG
        
    def get_ngrams(self, sequence, n=2):
        if len(sequence) < n:
            return [str(sequence)]
        return [str(sequence[i:i+n]) for i in range(len(sequence) - n + 1)]
        
    def compute_empirical_transitions(self):
        """Compute empirical transition matrix from observed sequence"""
        if len(self.sequence) < 2:
            self.transition_matrix = np.zeros((self.n_states, self.n_states))
            return self.transition_matrix
            
        # Initialize transition count matrix
        transition_counts = np.zeros((self.n_states, self.n_states))
        
        # Count transitions
        for i in range(len(self.sequence) - 1):
            current_state = self.sequence[i]
            next_state = self.sequence[i + 1]
            if 0 <= current_state < self.n_states and 0 <= next_state < self.n_states:
                transition_counts[current_state, next_state] += 1
        
        # Convert to probabilities (add smoothing to avoid zeros)
        smoothing = self.config['processing']['laplace_smoothing']
        transition_probs = transition_counts + smoothing  # Use config for smoothing
        row_sums = transition_probs.sum(axis=1, keepdims=True)
        # Avoid division by zero
        row_sums[row_sums == 0] = 1
        transition_probs = transition_probs / row_sums
        
        self.transition_matrix = transition_probs
        return transition_probs
    
    def compute_state_distribution(self):
        """Compute state distribution (frequency of each state)
        input: None
        output: state_distribution (numpy array of state frequencies)
        """
        if len(self.sequence) == 0:
            return np.zeros(self.n_states)
        
        state_counts = np.bincount(self.sequence, minlength=self.n_states)
        self.state_distribution = state_counts / len(self.sequence)
        return self.state_distribution
    
    def compute_complexity_features(self):
        """Compute enhanced complexity features for better clustering"""
        if len(self.sequence) == 0:
            self.complexity_features = np.zeros(15)
            self.complexity_features_normalized = np.zeros(15)
            return self.complexity_features
        
        features = []
        
        # 1. Sequence length (normalized)
        features.append(len(self.sequence))
        
        # 2. Number of unique states
        unique_states = len(np.unique(self.sequence))
        features.append(unique_states)
        
        # 3. State diversity ratio (unique states / total length)
        state_diversity = unique_states / len(self.sequence)
        features.append(state_diversity)
        
        # 4. Entropy of state distribution
        state_dist = self.compute_state_distribution()
        epsilon = self.config['processing']['entropy_epsilon']
        entropy = -np.sum(state_dist * np.log(state_dist + epsilon))
        features.append(entropy)
        
        # 5. Number of state changes
        state_changes = np.sum(self.sequence[:-1] != self.sequence[1:])
        features.append(state_changes)
        
        # 6. Change ratio (state changes / total length)
        change_ratio = state_changes / len(self.sequence) if len(self.sequence) > 0 else 0
        features.append(change_ratio)
        
        # 7. Average run length (consecutive same states)
        run_lengths = []
        current_run = 1
        for i in range(1, len(self.sequence)):
            if self.sequence[i] == self.sequence[i-1]:
                current_run += 1
            else:
                run_lengths.append(current_run)
                current_run = 1
        run_lengths.append(current_run)
        avg_run_length = np.mean(run_lengths) if run_lengths else 1
        features.append(avg_run_length)
        
        # 8. Maximum run length
        max_run_length = np.max(run_lengths) if run_lengths else 1
        features.append(max_run_length)
        
        # 9. Run length variance
        run_length_var = np.var(run_lengths) if len(run_lengths) > 1 else 0
        features.append(run_length_var)
        
        # 10. Pattern complexity (Lempel-Ziv complexity approximation)
        pattern_complexity = self._compute_pattern_complexity()
        features.append(pattern_complexity)
        
        # 11. Repetition score (how repetitive the sequence is)
        repetition_score = self._compute_repetition_score()
        features.append(repetition_score)
        
        # 12. Transition entropy
        if hasattr(self, 'transition_matrix') and self.transition_matrix is not None:
            epsilon = self.config['processing']['entropy_epsilon']
            trans_entropy = -np.sum(self.transition_matrix * np.log(self.transition_matrix + epsilon))
        else:
            trans_entropy = 0
        features.append(trans_entropy)
        
        # 13. Self-transition ratio
        self_transitions = np.sum(self.sequence[:-1] == self.sequence[1:])
        self_transition_ratio = self_transitions / len(self.sequence) if len(self.sequence) > 0 else 0
        features.append(self_transition_ratio)
        
        # 14. Periodicity score (how often elements repeat after a fixed distance/period)
        periodicity = self._compute_periodicity()
        features.append(periodicity)
        
        # 15. Workflow phase dominance (most frequent state ratio)
        most_frequent_ratio = np.max(state_dist) if len(state_dist) > 0 else 0
        features.append(most_frequent_ratio)
        
        self.complexity_features = np.array(features)
        self.complexity_features_normalized = (self.complexity_features 
                                               / (np.linalg.norm(self.complexity_features) + 1e-10))
        return self.complexity_features
    
    def _compute_pattern_complexity(self):
        """Approximation of Lempel-Ziv complexity"""
        if len(self.sequence) <= 1:
            return 0
        
        substrings = set()
        for i in range(len(self.sequence)):
            for j in range(i+1, len(self.sequence)+1):
                substrings.add(tuple(self.sequence[i:j]))
        
        return len(substrings) / (len(self.sequence) ** 2)
    
    def _compute_repetition_score(self):
        """Compute how repetitive the sequence is"""
        if len(self.sequence) <= 2:
            return 0
        
        # Look for repeated subsequences
        max_repetition = 0
        for length in range(1, len(self.sequence) // 2 + 1):
            for start in range(len(self.sequence) - length + 1):
                pattern = tuple(self.sequence[start:start + length])
                count = 0
                for i in range(len(self.sequence) - length + 1):
                    if tuple(self.sequence[i:i + length]) == pattern:
                        count += 1
                repetition_ratio = (count * length) / len(self.sequence)
                max_repetition = max(max_repetition, repetition_ratio)
        
        return max_repetition
    
    def _compute_periodicity(self):
        """Compute periodicity of the sequence"""
        if len(self.sequence) <= 2:
            return 0
        
        max_periodicity = 0
        for period in range(1, len(self.sequence) // 2 + 1):
            matches = 0
            comparisons = 0
            for i in range(len(self.sequence) - period):
                if self.sequence[i] == self.sequence[i + period]:
                    matches += 1
                comparisons += 1
            
            if comparisons > 0:
                periodicity = matches / comparisons
                max_periodicity = max(max_periodicity, periodicity)
        
        return max_periodicity

class HMMClusterer:
    """Main clustering class supporting multiple algorithms"""
    
    def __init__(self, config=None):
        # Use provided config or global config
        self.config = config if config is not None else CONFIG
        
        # Extract clustering parameters from config
        clustering_config = self.config['clustering']
        self.max_cluster_size = clustering_config['max_cluster_size']
        self.min_cluster_size = clustering_config['min_cluster_size']
        self.initial_clusters = clustering_config['initial_clusters']
        self.refinement_threshold = clustering_config['refinement_threshold']
        self.linkage_method = clustering_config['linkage_method']
        
        # Extract similarity methods
        similarity_config = self.config['similarity_methods']
        self.transition_method = similarity_config['transition_matrix_method']
        self.ngram_sizes = similarity_config['ngram_sizes']
        
        # Extract processing parameters
        processing_config = self.config['processing']
        self.state_min = processing_config['state_range']['min']
        self.state_max = processing_config['state_range']['max']
        self.laplace_smoothing = processing_config['laplace_smoothing']
        self.entropy_epsilon = processing_config['entropy_epsilon']
        self.min_sequence_length = processing_config['min_sequence_length']
        
        # Extract distance weights
        self.individual_weights = self.config['distance_weights']['individual_notebooks']
        self.cluster_weights = self.config['distance_weights']['inter_cluster']
        
        print(f"Initialized HMMClusterer with:")
        print(f"  Max cluster size: {self.max_cluster_size}")
        print(f"  Initial clusters: {self.initial_clusters}")
        print(f"  Transition method: {self.transition_method}")
        print(f"  State range: {self.state_min}-{self.state_max}")
        
        # Load state names from class_mapping.json
        try:
            with open('./class_mapping.json', 'r') as f:
                class_mapping = json.load(f)
            self.state_names = list(class_mapping.keys())
            print(f"Loaded {len(self.state_names)} state names from class_mapping.json: {self.state_names}")
        except FileNotFoundError:
            # Fallback state names
            self.state_names = [f"state_{i}" for i in range(12)]
            print(f"Warning: Could not load class_mapping.json, using fallback state names: {self.state_names}")
    
    def load_notebook_sequences(self, file_base):
        """Load notebook sequences from CSV file"""
        cells = pd.read_csv(file_base + "Cells_predicted.csv", 
                            usecols=["KernelVersionId", "MainLabel"],
                            dtype={
                                "KernelVersionId": "Int32",
                                "MainLabel": "Int32"}
                            ).dropna()
        cells = cells[cells["KernelVersionId"].isin(KERNEL_IDS)]
        
        label_ids = (cells.groupby("KernelVersionId", as_index=False)
            .agg(
                label_ids=("MainLabel", list)
            ))
            
        inferred_n_states = 12  # Default fallback
        
        notebooks = []
        
        for _, row in label_ids.iterrows():
            try:
                sequence = [int(x) for x in row['label_ids']]
                if len(sequence) > 0:  # Only include non-empty sequences
                    # Filter out invalid states using config
                    valid_sequence = [s for s in sequence if self.state_min <= s <= self.state_max]
                    if len(valid_sequence) >= self.min_sequence_length:  # Use config for min length
                        notebook = NotebookSequence(row['KernelVersionId'], valid_sequence, n_states=inferred_n_states, config=self.config)
                        # Compute features immediately
                        notebook.compute_empirical_transitions()
                        notebook.compute_state_distribution()
                        notebook.compute_complexity_features()
                        notebooks.append(notebook)
            except Exception as e:
                print(f"Error processing kernel {row['kernelVersionId']}: {e}")
                continue
        
        return notebooks
    
    def calculate_transition_similarity(self, trans1, trans2, method='frobenius'):
        """Calculate similarity between two transition matrices"""
        # Handle None values
        if trans1 is None or trans2 is None:
            return 1.0  # Maximum distance for None matrices
        
        if method == 'frobenius':
            # Frobenius norm distance
            return np.linalg.norm(trans1 - trans2, 'fro')
        elif method == 'kl_divergence':
            # Average KL divergence between rows
            kl_sum = 0
            valid_rows = 0
            for i in range(trans1.shape[0]):
                if np.sum(trans1[i]) > 0 and np.sum(trans2[i]) > 0:
                    # Add small epsilon to avoid log(0)
                    p1 = trans1[i] + 1e-10
                    p2 = trans2[i] + 1e-10
                    p1 = p1 / np.sum(p1)
                    p2 = p2 / np.sum(p2)
                    kl_sum += np.sum(p1 * np.log(p1 / p2))
                    valid_rows += 1
            return kl_sum / valid_rows if valid_rows > 0 else 0
        elif method == 'cosine':
            # Cosine distance between flattened matrices
            flat1 = trans1.flatten()
            flat2 = trans2.flatten()
            dot_product = np.dot(flat1, flat2)
            norm1 = np.linalg.norm(flat1)
            norm2 = np.linalg.norm(flat2)
            if norm1 == 0 or norm2 == 0:
                return 1.0
            return 1 - (dot_product / (norm1 * norm2))
    
    def levenshtein_distance(self, seq1, seq2):
        """Compute Levenshtein (edit) distance between two sequences"""
        if len(seq1) < len(seq2):
            return self.levenshtein_distance(seq2, seq1)
        
        if len(seq2) == 0:
            return len(seq1)
        
        previous_row = list(range(len(seq2) + 1))
        for i, c1 in enumerate(seq1):
            current_row = [i + 1]
            for j, c2 in enumerate(seq2):
                insertions = previous_row[j + 1] + 1
                deletions = current_row[j] + 1
                substitutions = previous_row[j] + (c1 != c2)
                current_row.append(min(insertions, deletions, substitutions))
            previous_row = current_row
        
        return previous_row[-1]
    
    def compute_pattern_similarity(self, ngrams1, ngrams2):
        """Compute pattern similarity using n-grams"""
        
        if len(ngrams1) == 0 and len(ngrams2) == 0:
            return 0
        
        # Jaccard distance
        intersection = len(ngrams1.intersection(ngrams2))
        union = len(ngrams1.union(ngrams2))
        
        if union == 0:
            return 0
        
        return 1 - (intersection / union)
    
    def compute_distance_matrix(self, notebooks):
        """Compute enhanced distance matrix between all notebooks"""
        n = len(notebooks)
        distance_matrix = np.zeros((n, n))
        
        complexity = np.vstack([n.complexity_features_normalized for n in notebooks])
        state = np.vstack([n.state_distribution for n in notebooks])
        complexity_dm = cdist(complexity, complexity, metric="euclidean")
        state_dm = cdist(state, state, metric="euclidean")
        
        for i, n1 in tqdm(enumerate(notebooks), desc="Computing distance matrix", total=len(notebooks)):
            for j_, n2 in enumerate(notebooks[i+1:]):
                j = j_ + i + 1
                # Enhanced distance calculation with sophisticated features
                
                # 1. Sequence similarity using edit distance
                seq1 = n1.sequence
                seq2 = n2.sequence
                edit_dist = Levenshtein.distance(seq1, seq2)
                max_len = max(len(seq1), len(seq2))
                normalized_edit_dist = edit_dist / max_len if max_len > 0 else 0
                
                # 2. Complexity feature similarity
                complexity_dist = complexity_dm[i, j]
                # comp1 = n1.complexity_features_normalized
                # comp2 = n2.complexity_features_normalized
                # complexity_dist = np.linalg.norm(comp1 - comp2)
                
                # 3. State distribution similarity
                state_dist = state_dm[i, j]
                # dist1 = n1.state_distribution
                # dist2 = n2.state_distribution
                # state_dist = np.linalg.norm(dist1 - dist2)
                
                # 4. Transition matrix similarity
                trans1 = n1.transition_matrix
                trans2 = n2.transition_matrix
                trans_dist = self.calculate_transition_similarity(trans1, trans2, method=self.transition_method)
                
                # 5. Length similarity (penalize very different lengths)
                len1, len2 = len(seq1), len(seq2)
                length_ratio = min(len1, len2) / max(len1, len2) if max(len1, len2) > 0 else 1
                length_dist = 1 - length_ratio
                
                # 6. Pattern similarity using n-grams
                ngrams_1 = n1.sequence_ngrams
                ngrams_2 = n2.sequence_ngrams
                pattern_dist = self.compute_pattern_similarity(ngrams_1, ngrams_2)
                
                # Combine distances with weights from config
                weights = self.individual_weights
                combined_dist = (weights['edit_distance'] * normalized_edit_dist +
                                weights['complexity_features'] * complexity_dist +
                                weights['state_distribution'] * state_dist +
                                weights['transition_matrix'] * trans_dist +
                                weights['length_similarity'] * length_dist +
                                weights['pattern_similarity'] * pattern_dist)
                
                distance_matrix[i, j] = combined_dist
                distance_matrix[j, i] = combined_dist
        
        return distance_matrix
    
    def cluster_notebooks(self, notebooks, distance_matrix, n_clusters=None):
        """Cluster notebooks using adaptive hierarchical clustering with refinement"""
        return self.hierarchical_clustering_with_refinement(notebooks, distance_matrix)
    
    def hierarchical_clustering_with_refinement(self, notebooks, distance_matrix):
        """Perform hierarchical clustering with cluster refinement"""
        
        # Converts a square distance matrix into a condensed (1D) format
        condensed_dist = squareform(distance_matrix)
        # Performs hierarchical clustering to build a dendrogram tree
        linkage_matrix = linkage(condensed_dist, method=self.linkage_method)
        # Cuts the hierarchical tree to form flat clusters
        cluster_labels = fcluster(linkage_matrix, self.initial_clusters, criterion='maxclust')
        
        print(f"Initial clustering: {len(np.unique(cluster_labels))} clusters")
        
        # Refine clusters that have high internal distance
        refined_labels = cluster_labels.copy()
        next_cluster_id = max(cluster_labels) + 1
        
        for cluster_id in np.unique(cluster_labels):
            cluster_indices = np.where(cluster_labels == cluster_id)[0]
            
            if len(cluster_indices) <= 2:  # Skip very small clusters
                continue
            
            # Calculate average internal distance
            cluster_distances = []
            for i in range(len(cluster_indices)):
                for j in range(i + 1, len(cluster_indices)):
                    idx1, idx2 = cluster_indices[i], cluster_indices[j]
                    cluster_distances.append(distance_matrix[idx1, idx2])
            
            avg_internal_distance = np.mean(cluster_distances) if cluster_distances else 0
            
            # If average internal distance is high and cluster is large, try to split
            if (avg_internal_distance > self.refinement_threshold or
                len(cluster_indices) > self.max_cluster_size):
                
                print(f"Refining cluster {cluster_id} (avg_dist: {avg_internal_distance:.3f}, size: {len(cluster_indices)})")
                
                # Extract sub-distance matrix for this cluster
                sub_distance_matrix = distance_matrix[np.ix_(cluster_indices, cluster_indices)]
                
                # Try to split into 2 sub-clusters
                n_subclusters = 2
                print(f"  Split into {n_subclusters} sub-clusters")
                sub_condensed = squareform(sub_distance_matrix)
                sub_linkage = linkage(sub_condensed, method=self.linkage_method)
                sub_labels = fcluster(sub_linkage, n_subclusters, criterion='maxclust')
                
                # Apply the split - only reassign non-first clusters
                for sub_id in np.unique(sub_labels)[1:]:  # Skip first cluster (ID 1)
                    sub_mask = sub_labels == sub_id
                    refined_labels[cluster_indices[sub_mask]] = next_cluster_id
                    next_cluster_id += 1
        
        print(f"After refinement: {len(np.unique(refined_labels))} clusters")
        return refined_labels, linkage_matrix
    
    def calculate_inter_cluster_distances(self, notebooks, cluster_labels):
        """Calculate distance matrix between clusters based on their centroids"""
        unique_clusters = np.unique(cluster_labels)
        n_clusters = len(unique_clusters)
        cluster_distance_matrix = np.zeros((n_clusters, n_clusters))
        
        # Calculate cluster centroids for different feature types
        cluster_centroids = {}
        
        for i, cluster_id in enumerate(unique_clusters):
            cluster_notebooks = [notebooks[j] for j, label in enumerate(cluster_labels) if label == cluster_id]
            
            if not cluster_notebooks:
                continue
            
            # Calculate centroid features
            complexity_features = np.array([nb.complexity_features for nb in cluster_notebooks])
            state_distributions = np.array([nb.state_distribution for nb in cluster_notebooks])
            transition_matrices = np.array([nb.transition_matrix for nb in cluster_notebooks])
            
            centroid = {
                'complexity': np.mean(complexity_features, axis=0),
                'state_dist': np.mean(state_distributions, axis=0),
                'transition': np.mean(transition_matrices, axis=0),
                'avg_length': np.mean([len(nb.sequence) for nb in cluster_notebooks])
            }
            
            cluster_centroids[cluster_id] = centroid
        
        # Calculate distances between cluster centroids
        print("Computing inter-cluster distances...")
        for i, cluster_i in enumerate(unique_clusters):
            for j, cluster_j in enumerate(unique_clusters):
                if i == j:
                    cluster_distance_matrix[i, j] = 0
                elif i < j:  # Only compute upper triangle
                    centroid_i = cluster_centroids[cluster_i]
                    centroid_j = cluster_centroids[cluster_j]
                    
                    # Calculate distance using same metrics as individual notebooks
                    # 1. Complexity feature similarity
                    comp_dist = np.linalg.norm(centroid_i['complexity'] - centroid_j['complexity'])
                    
                    # 2. State distribution similarity
                    state_dist = np.linalg.norm(centroid_i['state_dist'] - centroid_j['state_dist'])
                    
                    # 3. Transition matrix similarity
                    trans_dist = np.linalg.norm(centroid_i['transition'] - centroid_j['transition'], 'fro')
                    
                    # 4. Length similarity
                    length_diff = abs(centroid_i['avg_length'] - centroid_j['avg_length'])
                    max_length = max(centroid_i['avg_length'], centroid_j['avg_length'])
                    length_dist = length_diff / max_length if max_length > 0 else 0
                    
                    # Combine distances with weights from config
                    weights = self.cluster_weights
                    combined_dist = (weights['complexity_features'] * comp_dist +
                                   weights['state_distribution'] * state_dist +
                                   weights['transition_matrix'] * trans_dist +
                                   weights['length_similarity'] * length_dist)
                    
                    cluster_distance_matrix[i, j] = combined_dist
                    cluster_distance_matrix[j, i] = combined_dist  # Symmetric matrix
        
        return cluster_distance_matrix, unique_clusters
    
    def get_cluster_ordering_by_similarity(self, cluster_distance_matrix, unique_clusters):
        """Order clusters by similarity using hierarchical clustering on cluster centroids"""
        if len(unique_clusters) <= 1:
            return unique_clusters
        
        # Perform hierarchical clustering on cluster distance matrix
        condensed_cluster_dist = squareform(cluster_distance_matrix)
        cluster_linkage = linkage(condensed_cluster_dist, method=self.linkage_method)
        
        # Get the order of clusters from the dendrogram
        dendro = dendrogram(cluster_linkage, no_plot=True)
        cluster_order_indices = dendro['leaves']
        
        # Map back to original cluster IDs
        ordered_clusters = [unique_clusters[i] for i in cluster_order_indices]
        
        print(f"Cluster similarity ordering: {ordered_clusters}")
        return ordered_clusters
    
    def group_clusters(self, results_df, notebooks, cluster_labels):
        """Group clusters by similarity and sort by sequence length within each cluster
        
        Args:
            results_df: DataFrame with clustering results
            notebooks: List of NotebookSequence objects
            cluster_labels: Array of cluster assignments
            
        Returns:
            DataFrame: Grouped and sorted results with similar clusters adjacent
        """
        # Calculate inter-cluster distances and get similarity ordering
        cluster_distance_matrix, unique_clusters = self.calculate_inter_cluster_distances(notebooks, cluster_labels)
        ordered_clusters = self.get_cluster_ordering_by_similarity(cluster_distance_matrix, unique_clusters)
        
        # Create a mapping for cluster ordering
        cluster_order_map = {cluster_id: i for i, cluster_id in enumerate(ordered_clusters)}
        
        # Add cluster size and order columns for sorting
        results_df['cluster_order'] = results_df['cluster_id'].map(cluster_order_map)
        
        # Sort using config parameters
        sorting_config = self.config['sorting']
        grouped_df = results_df.sort_values(
            sorting_config['cluster_order_columns'],
            ascending=sorting_config['cluster_order_ascending']
        )
        
        # Remove the temporary ordering column
        grouped_df = grouped_df.drop('cluster_order', axis=1)
        
        # Reorder columns as requested
        column_order = ['kernelVersionId', 'cluster_id', 'sequence_length', 'most_common_state', 'sequence', 'state_distribution', 'complexity_features']
        grouped_df = grouped_df[column_order]
        
        return grouped_df

    def save_results(self, notebooks, cluster_labels, output_prefix='hmm_clustering'):
        """Save clustering results to files"""
        
        # Calculate most common state for each cluster
        cluster_most_common = {}
        for cluster_id in np.unique(cluster_labels):
            cluster_sequences = [notebooks[i].sequence for i, label in enumerate(cluster_labels) if label == cluster_id]
            if cluster_sequences:
                all_states = np.concatenate(cluster_sequences)
                most_common_state_idx = np.bincount(all_states).argmax()
                # Get state name if available, otherwise use index
                if hasattr(self, 'state_names') and most_common_state_idx < len(self.state_names):
                    cluster_most_common[cluster_id] = self.state_names[most_common_state_idx]
                else:
                    cluster_most_common[cluster_id] = f"state_{most_common_state_idx}"
        
        # Create results DataFrame
        results_data = []
        for i, notebook in enumerate(notebooks):
            data = {
                'kernelVersionId': notebook.kernel_id,
                'cluster_id': cluster_labels[i],
                'sequence_length': len(notebook.sequence),
                'most_common_state': cluster_most_common.get(cluster_labels[i], 'unknown'),
                'sequence': notebook.sequence.tolist(),
                'state_distribution': notebook.state_distribution.tolist(),
                'complexity_features': notebook.complexity_features.tolist()
            }
            
            results_data.append(data)
        
        results_df = pd.DataFrame(results_data)
        
        # Group and sort the results using cluster similarity
        grouped_df = self.group_clusters(results_df, notebooks, cluster_labels)
        
        # Save grouped results
        grouped_df.to_csv(f'{output_prefix}_clustered.csv', index=False)
        print(f"Results saved to ../results/{output_prefix}_clustered.csv")
        # print(f"Cluster distances saved to ../results/{output_prefix}_cluster_distances.csv")
        
        return grouped_df

def main():
    """Main function to run the enhanced HMM clustering analysis"""
    
    # Load configuration
    config = load_config()
    
    # Initialize clusterer with config
    clusterer = HMMClusterer(config=config)
    
    # Set random seed from config
    random_seed = config['random_seed']
    np.random.seed(random_seed)
    print(f"Set random seed to: {random_seed}")
    
    print("="*80)
    print("RUNNING ENHANCED HMM CLUSTERING")
    print("="*80)
    
    # Load notebooks with enhanced features
    print("Loading notebook sequences with enhanced features...")
    notebooks = clusterer.load_notebook_sequences("/media/tim/Data/Thesis/")
    print(f"Loaded {len(notebooks)} valid notebook sequences")
    
    if len(notebooks) >= 2:
        # Compute enhanced distance matrix
        print("Computing enhanced distance matrix...")
        distance_matrix = clusterer.compute_distance_matrix(notebooks)
        
        # Perform adaptive clustering with refinement
        print("Performing adaptive clustering with refinement...")
        cluster_labels, linkage_matrix = clusterer.cluster_notebooks(notebooks, distance_matrix)
        
        print(f"Found {len(np.unique(cluster_labels))} clusters")
        
        # Save results
        print("Saving results...")
        results_df = clusterer.save_results(notebooks, cluster_labels)
        
        print("Enhanced clustering analysis complete!")
    else:
        print("Not enough notebooks for clustering analysis")
    
    print("\nAnalysis complete!")

if __name__ == "__main__":
    main()
